ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN ManagerID COMMENT 'Sales/account manager assigned to this customer. FK to BackOffice.Manager(ManagerID). NULL = unassigned. Included in IX_H_BackOfficeCustomer for fast manager lookups. References BackOffice.Manager. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN IsAffiliate COMMENT 'Whether this customer was referred through an affiliate program. Default=0 (not affiliate). Affects fee structures and reporting. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN Cleared COMMENT 'AML/compliance clearance flag. Default=0. Set to 1 when the customer has passed AML checks. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN Verified COMMENT 'KYC verification flag. Default=0. Set to 1 when the customer''s identity has been fully verified. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN PreviousManagerID COMMENT 'The manager who was assigned to this customer before the current ManagerID. Used to track manager reassignment history. References BackOffice.Manager. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN FXEligibilityDate COMMENT 'Date when this customer became eligible for FX trading. NULL = not yet eligible. Set based on regulation/verification requirements. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN AffiliateManagerID COMMENT 'Manager ID for the affiliate who referred this customer. NULL for non-affiliate customers. References BackOffice.Manager. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN CashoutFeeGroupID COMMENT 'Fee tier for withdrawal charges. FK to Dictionary.CashoutFeeGroup(CashoutFeeGroupID). NULL = default fee group. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN AccountTypeID COMMENT 'Customer account type. From _glossary.md: 1=Real, 2=Demo, 3=None, 5=VirtualCfd... (16 total values). The COLUMNSTORE index covers ValidFrom, ValidTo, CID, AccountTypeID for DWH aggregations. Also covered by separate nonclustered index on BackOffice.Customer. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN MasterAccountCID COMMENT 'CID of the master/parent account if this is a sub-account. NULL for standalone accounts. Used in multi-account customer structures. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN ManagerPermitID COMMENT 'Permission level of the assigned manager. Default=1 (standard permit). Controls what actions the manager can perform on this customer. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN ThirdPartyManagerComment COMMENT 'Free-text comment from a third-party manager (e.g., IB/introducer). Used when the customer was referred by an external partner. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN GuruStatusID COMMENT 'Popular Investor / Guru status for CopyTrading. FK to Dictionary.GuruStatus. NULL = regular trader. Non-null = has guru/popular investor status at a specific level. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN RiskClassificationID COMMENT 'Risk classification for regulatory purposes. FK to Dictionary.RiskClassification(RiskClassificationID). Default=0. Written by BackOffice.SetRiskClassificationNew and RiskCalculation procedures. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN VerificationLevelID COMMENT 'KYC verification level. 0=Level 0 (unverified/basic). Higher values = more documents verified. References Dictionary.VerificationLevel. Covered by IX_HistoryBackOfficeCustomer (ValidFrom, includes CID, VerificationLevelID). (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN RegulationID COMMENT 'Primary regulatory jurisdiction. Known values: 1=Cyprus CySEC, 2=EU, 4=Australia ASIC, 5=UK FCA, 10=Global/Offshore, 11=US Apex. Determines product eligibility, leverage limits, and reporting requirements. Covered in Idx_History_BackOfficeCustomer_CID_ValidFrom_ValidTo INCLUDE. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN RiskStatusID COMMENT 'Operational risk status (different from RiskClassificationID which is regulatory). Controls account restrictions, trading limits. References Dictionary.RiskStatus (if exists). (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN AcceptanceStatusID COMMENT 'KYC/compliance acceptance decision. 0=Pending, 1=Accepted, 2=Rejected, 3=Follow Up. References Dictionary.AcceptanceStatus. Set by compliance team after document review. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN DocumentStatusID COMMENT 'Status of the customer''s submitted identity documents. NULL = no documents submitted. References Dictionary.DocumentStatus. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN PhoneVerifiedID COMMENT 'Phone number verification status. NULL = not verified. Non-null = verification method and status. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN AcceptanceStatusChanginManagerID COMMENT 'Manager ID who changed the AcceptanceStatus. References BackOffice.Manager. Provides accountability for compliance decisions. Note: typo in column name ("Changin" instead of "Changing"). (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN GDCCheckID COMMENT 'Global Data Check (GDC) or sanctions screening result ID. AML-related check. References Dictionary or BackOffice check tables. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN SuitabilityTestStatusID COMMENT 'Regulatory suitability/appropriateness test status. Required under MiFID II for professional categorization. References Dictionary.SuitabilityTestStatus. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN EvMatchStatus COMMENT 'Electronic verification (eV) match status. Anti-fraud identity verification match result. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN Lei COMMENT 'Legal Entity Identifier (LEI) for institutional/corporate customers. 20-character ISO 17442 code. Required for MiFID II transaction reporting for legal entities. NULL for retail/individual accounts. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN MifidCategorizationID COMMENT 'EU MiFID II client categorization. FK to Dictionary.MifidCategorization. 1=Retail, 2=Professional (per se), 3=Eligible Counterparty, 4=Not Applicable (non-EU), 5=Elected Professional. Determines leverage limits and protections under EU regulation. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN DesignatedRegulationID COMMENT 'Override regulation for customers subject to a specific regulatory regime different from their primary RegulationID. NULL = follow primary RegulationID. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN Trace COMMENT 'Connection context JSON: {"HostName","AppName","SUserName","OriginalLogin","SPID","DBName","ObjectName"}. Automatically populated by the DEFAULT constraint at INSERT time. Enables tracing which application path (stored procedure, service, DBA tool) triggered each state change. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN AMLComment COMMENT 'Anti-Money Laundering free-text comment. Written by compliance team. May contain investigation notes, screening results, or manual review findings. Up to 8000 characters. Covered in Idx_History_BackOfficeCustomer_CID_ValidFrom_ValidTo INCLUDE. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN HasWallet COMMENT 'Whether this customer has an eToro Money wallet. NULL/0=no wallet, 1=has wallet. Part of the eToro Money crypto wallet product. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN SalesForceAccountID COMMENT 'Salesforce CRM Account object ID (18-character Salesforce ID). Links this customer to their Salesforce record. NULL for customers not yet synced to Salesforce. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN SalesForceContactID COMMENT 'Salesforce CRM Contact object ID (18-character). The Contact record linked to this customer in Salesforce. NULL for unsynced customers. Written/read by Maintenance.JOB_SendCustomerXMLToCRM and SalesForce.GetBackOfficeCustomer. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
ALTER TABLE main.general.bronze_etoro_history_backofficecustomer ALTER COLUMN AsicClassificationID COMMENT 'Australian ASIC client classification. NULL=not applicable (non-AU), 4=retail, other values=wholesale/sophisticated investor. Determines leverage limits under ASIC RG168. (Tier 1 - upstream wiki, etoro.History.BackOfficeCustomer)';
